// Filter videos published in the last 24h and extract video IDs
const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
const channelId = $('Get Active Channels').item.json.channel_id;
const channelName = $('Get Active Channels').item.json.channel_name;

const results = [];
for (const item of $input.all()) {
  const pub = new Date(item.json.isoDate || item.json.pubDate || 0);
  if (pub > cutoff) {
    const url = item.json.link || '';
    const videoId = url.split('v=')[1]?.split('&')[0] || '';
    if (videoId) {
      results.push({
        json: {
          video_id: videoId,
          video_url: url,
          video_title: item.json.title || '',
          channel_id: channelId,
          channel_name: channelName,
          pub_date: item.json.isoDate || item.json.pubDate || new Date().toISOString()
        }
      });
    }
  }
}

return results;

// Fetch YouTube transcript via InnerTube API (Android client)
const videoUrl = $json.video_url;
const videoId = videoUrl.split('v=')[1]?.split('&')[0];
if (!videoId) throw new Error('Invalid YouTube URL: ' + videoUrl);

const playerRes = await fetch('https://www.youtube.com/youtubei/v1/player?prettyPrint=false', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'User-Agent': 'com.google.android.youtube/20.10.38 (Linux; U; Android 14)'
  },
  body: JSON.stringify({
    context: { client: { clientName: 'ANDROID', clientVersion: '20.10.38' } },
    videoId
  })
});
const playerData = await playerRes.json();
const tracks = playerData?.captions?.playerCaptionsTracklistRenderer?.captionTracks;
if (!tracks?.length) throw new Error('No caption tracks for video: ' + videoId);

const track = tracks.find(t => t.languageCode === 'en') || tracks[0];
const captionRes = await fetch(track.baseUrl, {
  headers: { 'User-Agent': 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10_15_4) AppleWebKit/537.36' }
});
const captionXml = await captionRes.text();

const transcript = [...captionXml.matchAll(/<s[^>]*>([^<]*)<\/s>/g)]
  .map(m => m[1])
  .join('')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'").replace(/&quot;/g, '"')
  .replace(/\s+/g, ' ')
  .trim();

if (!transcript) throw new Error('Empty transcript for video: ' + videoId);

return [{
  json: {
    ...$json,
    transcript
  }
}];

