// Assemble blog post content for jwd.nyc from the Gemini analysis
const analysis = $('Parse Gemini Analysis').item.json;
const post = $('Write LinkedIn Post').item.json.output;
const video = $('Filter Recent Videos').item.json;
const wpImageId = $('Upload Image to jwd.nyc').item.json.id;
const imageUrl = $('Upload Image to jwd.nyc').item.json.guid?.raw || '';

// Generate URL slug: speaker-name-video-id
const speakerSlug = analysis.speaker_name
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');
const slug = `${speakerSlug}-${video.video_id}`;
const jwd_blog_url = `https://jwd.nyc/${slug}/`;

// Build HTML content
const quotesHtml = analysis.top_quotes
  .map(q => `<blockquote><p>${q}</p></blockquote>`)
  .join('\n');

const insightsHtml = analysis.key_insights
  .map(k => `<li>${k}</li>`)
  .join('\n');

const hashtagsText = post.hashtags.map(h => `#${h}`).join(' ');

const content = `<p>${analysis.narrative_summary}</p>

<h2>Key Quotes from ${analysis.speaker_name}</h2>
${quotesHtml}

<h2>Key Takeaways</h2>
<ul>
${insightsHtml}
</ul>

<h2>Most Surprising Statement</h2>
<blockquote><p>${analysis.surprising_statement}</p></blockquote>

<h2>Watch the Full Interview</h2>
<p><a href="${video.video_url}" target="_blank" rel="noopener">Watch on YouTube →</a></p>

<hr>

<p>${post.post_text.replace(/\n/g, '</p>\n<p>')}</p>

<p><em>${hashtagsText}</em></p>`;

// X post: opening quote + attribution + URL (fits in 280 chars)
const firstLine = post.post_text.split('\n')[0] || post.post_text.substring(0, 220);
const xPost = `${firstLine}\n\n${video.video_url}`;

return [{
  json: {
    video_id: video.video_id,
    video_url: video.video_url,
    video_title: video.video_title,
    channel_id: video.channel_id,
    speaker_name: analysis.speaker_name,
    slug,
    jwd_blog_url,
    wp_image_id: wpImageId,
    image_url: imageUrl,
    title: post.post_title,
    content,
    post_text: post.post_text,
    x_post: xPost,
    hashtags: post.hashtags
  }
}];

